UPDATE ai_task
SET status = 'PROCESSING', worker_id = #{workerId}, lease_until = #{leaseUntil},
    attempt_count = attempt_count + 1, version = version + 1, updated_at = #{now}
WHERE task_id = #{taskId}
  AND version = #{expectedVersion}
  AND status IN ('PENDING', 'RETRY_WAIT', 'PROCESSING')
  AND (status != 'PROCESSING' OR lease_until IS NULL OR lease_until <= #{now})
